    """Convert a duration in seconds to beats (quarter notes) at ``bpm``."""
    if bpm <= 0:
        raise ValueError(f"bpm must be positive, got {bpm}")
    if seconds < 0:
        raise ValueError(f"seconds must be non-negative, got {seconds}")
    return seconds * bpm / 60.0


